import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const themeDir = path.join(root, "theme-data", "dexthemes");
const sourceFiles = [
  "helpers.js",
  "anime.js",
  "liger-zero.js",
  "games.js",
  "movies.js",
  "comics.js",
  "zodiacs.js",
  "lunar.js",
  "companies.js",
  "originals.js",
  "supporter.js",
];

export async function buildThemeBundle() {
  const sources = await Promise.all(
    sourceFiles.map((fileName) => readFile(path.join(themeDir, fileName), "utf8")),
  );
  const output = [
    "// Generated by scripts/build-theme-bundle.mjs. Edit the source pack files instead.\n",
    ...sources.map((source) => source.endsWith("\n") ? source : `${source}\n`),
  ].join("");
  await writeFile(path.join(themeDir, "bundle.js"), output);
}

if (import.meta.url === pathToFileURL(process.argv[1]).href) {
  await buildThemeBundle();
}
